"""Task status enumeration for the job processing system."""
from enum import Enum


class TaskStatus(Enum):
    """Possible states for a processing task."""
    PENDING = "pending"
    RUNNING = "running"
    SUCCESS = "success"
    FAILURE = "failure"
    CANCELLED = "cancelled"

    @classmethod
    def from_string(cls, value):
        """Create a TaskStatus from a string value."""
        for member in cls:
            if member.value == value:
                return member
        raise ValueError(f"Unknown status: {value}")

    def is_terminal(self):
        """Return True if this status is a final state."""
        return self in (TaskStatus.SUCCESS, TaskStatus.FAILURE, TaskStatus.CANCELLED)

    def is_active(self):
        """Return True if this status means the task is still in progress."""
        return self in (TaskStatus.PENDING, TaskStatus.RUNNING)

    def can_transition_to(self, target):
        """Check if transitioning to the target status is valid."""
        valid = {
            TaskStatus.PENDING: [TaskStatus.RUNNING, TaskStatus.CANCELLED],
            TaskStatus.RUNNING: [TaskStatus.SUCCESS, TaskStatus.FAILURE, TaskStatus.CANCELLED],
            TaskStatus.SUCCESS: [],
            TaskStatus.FAILURE: [TaskStatus.PENDING],  # retry
            TaskStatus.CANCELLED: [],
        }
        return target in valid.get(self, [])

