"""Job scheduler -- creates jobs and manages the job queue."""
from core.job import Job
from core.status import TaskStatus


class Scheduler:
    """Manages a queue of jobs and their lifecycle."""

    def __init__(self):
        self._jobs = {}
        self._queue = []
        self._next_id = 1

    def submit(self, name, payload=None):
        """Submit a new job. Returns the created Job."""
        job = Job(job_id=self._next_id, name=name, payload=payload)
        self._jobs[job.job_id] = job
        self._queue.append(job.job_id)
        self._next_id += 1
        return job

    def next_pending(self):
        """Get the next pending job from the queue."""
        for jid in self._queue:
            job = self._jobs[jid]
            if job.status == TaskStatus.PENDING:
                return job
        return None

    def cancel_job(self, job_id):
        """Cancel a job if it has not reached a terminal state."""
        job = self._jobs.get(job_id)
        if job is None:
            raise KeyError(f"Job {job_id} not found")
        if job.status.is_terminal():
            raise ValueError(f"Job {job_id} is already in terminal state: {job.status.value}")
        job.mark_cancelled()
        return job

    def retry_job(self, job_id):
        """Retry a failed job."""
        job = self._jobs.get(job_id)
        if job is None:
            raise KeyError(f"Job {job_id} not found")
        job.retry()
        self._queue.append(job.job_id)
        return job

    def get_job(self, job_id):
        """Retrieve a job by ID."""
        return self._jobs.get(job_id)

    def list_jobs(self, status_filter=None):
        """List jobs, optionally filtered by TaskStatus."""
        jobs = list(self._jobs.values())
        if status_filter is not None:
            if not isinstance(status_filter, TaskStatus):
                raise TypeError(f"Expected TaskStatus, got {type(status_filter)}")
            jobs = [j for j in jobs if j.status == status_filter]
        return jobs

    def count_by_status(self):
        """Return a dict of TaskStatus -> count."""
        counts = {}
        for status in TaskStatus:
            count = len([j for j in self._jobs.values() if j.status == status])
            if count > 0:
                counts[status.value] = count
        return counts

    def clear_completed(self):
        """Remove all jobs in terminal states."""
        terminal_ids = [
            jid for jid, job in self._jobs.items()
            if job.status.is_terminal()
        ]
        for jid in terminal_ids:
            del self._jobs[jid]
            if jid in self._queue:
                self._queue.remove(jid)
        return len(terminal_ids)

