"""Job executor -- picks up jobs and runs them."""
import traceback
from core.status import TaskStatus


class Executor:
    """Executes jobs from the scheduler."""

    def __init__(self, scheduler):
        self.scheduler = scheduler
        self._handlers = {}
        self.execution_log = []

    def register_handler(self, job_name, handler_fn):
        """Register a handler function for a job type."""
        self._handlers[job_name] = handler_fn

    def execute_next(self):
        """Execute the next pending job. Returns the job or None."""
        job = self.scheduler.next_pending()
        if job is None:
            return None

        handler = self._handlers.get(job.name)
        if handler is None:
            job.mark_running()
            job.mark_failure(f"No handler registered for job type: {job.name}")
            self.execution_log.append({
                "job_id": job.job_id,
                "status": TaskStatus.FAILURE.value,
                "error": f"No handler for {job.name}",
            })
            return job

        job.mark_running()
        try:
            result = handler(job.payload)
            job.mark_success(result)
            self.execution_log.append({
                "job_id": job.job_id,
                "status": TaskStatus.SUCCESS.value,
                "result": result,
            })
        except Exception as e:
            job.mark_failure(e)
            self.execution_log.append({
                "job_id": job.job_id,
                "status": TaskStatus.FAILURE.value,
                "error": str(e),
                "traceback": traceback.format_exc(),
            })
        return job

    def execute_all(self):
        """Execute all pending jobs. Returns list of executed jobs."""
        executed = []
        while True:
            job = self.execute_next()
            if job is None:
                break
            executed.append(job)
        return executed

    def get_log(self, status_filter=None):
        """Get execution log, optionally filtered by status string."""
        if status_filter is None:
            return list(self.execution_log)
        return [e for e in self.execution_log if e["status"] == status_filter]

    def success_count(self):
        """Count successful executions."""
        return len(self.get_log(TaskStatus.SUCCESS.value))

    def failure_count(self):
        """Count failed executions."""
        return len(self.get_log(TaskStatus.FAILURE.value))

