"""REST API endpoints for the job processing system."""
import json
import sys
import os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from core.status import TaskStatus
from services.scheduler import Scheduler
from services.executor import Executor
from services.monitor import Monitor


# Global instances for the API
_scheduler = None
_executor = None
_monitor = None


def init_api():
    """Initialize API with fresh scheduler, executor, and monitor."""
    global _scheduler, _executor, _monitor
    _scheduler = Scheduler()
    _executor = Executor(_scheduler)
    _monitor = Monitor(_scheduler)
    return _scheduler, _executor, _monitor


def handle_submit_job(request_body):
    """POST /jobs -- submit a new job."""
    data = json.loads(request_body)
    name = data.get("name")
    payload = data.get("payload", {})
    if not name:
        return 400, {"error": "Missing job name"}
    job = _scheduler.submit(name, payload)
    return 201, {
        "job_id": job.job_id,
        "status": TaskStatus.PENDING.value,
        "message": f"Job submitted with status {TaskStatus.PENDING.value}",
    }


def handle_get_job(job_id):
    """GET /jobs/:id -- get job details."""
    job = _scheduler.get_job(job_id)
    if job is None:
        return 404, {"error": "Job not found"}
    return 200, job.to_dict()


def handle_cancel_job(job_id):
    """POST /jobs/:id/cancel -- cancel a job."""
    try:
        job = _scheduler.cancel_job(job_id)
        return 200, {
            "job_id": job.job_id,
            "status": TaskStatus.CANCELLED.value,
            "message": f"Job cancelled (was {TaskStatus.PENDING.value} or {TaskStatus.RUNNING.value})",
        }
    except (KeyError, ValueError) as e:
        return 400, {"error": str(e)}


def handle_retry_job(job_id):
    """POST /jobs/:id/retry -- retry a failed job."""
    try:
        job = _scheduler.retry_job(job_id)
        return 200, {
            "job_id": job.job_id,
            "status": TaskStatus.PENDING.value,
            "message": f"Job reset from {TaskStatus.FAILURE.value} to {TaskStatus.PENDING.value}",
        }
    except (KeyError, ValueError) as e:
        return 400, {"error": str(e)}


def handle_list_jobs(status=None):
    """GET /jobs -- list jobs, optionally by status."""
    if status:
        try:
            filter_status = TaskStatus.from_string(status)
        except ValueError:
            return 400, {"error": f"Invalid status: {status}"}
        jobs = _scheduler.list_jobs(filter_status)
    else:
        jobs = _scheduler.list_jobs()
    return 200, {
        "jobs": [j.to_dict() for j in jobs],
        "count": len(jobs),
    }


def handle_get_report():
    """GET /report -- get status report."""
    return 200, _monitor.get_summary()


def handle_execute_next():
    """POST /execute -- execute next pending job."""
    job = _executor.execute_next()
    if job is None:
        return 200, {"message": "No pending jobs", "status": TaskStatus.PENDING.value}
    return 200, {
        "job_id": job.job_id,
        "status": job.status.value,
        "result": job.result,
        "error": job.error,
    }
